import { Link } from "react-router-dom";

function Navbar() {

    return (
        <nav style={{ padding: 20,background: "#282c34"}}>
            <Link to="/">Shapes</Link>
            <Link to="/new">New Shape</Link>
            <Link to="/complex-shapes">Complex Shapes</Link>
            <Link to="/complex-shapes/new">Create Complex Shape</Link>
        </nav>

    );

}

export default Navbar;
